import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.CHeM0PsO.js";const p=JSON.parse('{"title":"Initial Target User","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/product/target-user.md","filePath":"sovereign-os/product/target-user.md"}'),s={name:"sovereign-os/product/target-user.md"};function o(n,e,l,c,u,d){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="initial-target-user" tabindex="-1">Initial Target User <a class="header-anchor" href="#initial-target-user" aria-label="Permalink to &quot;Initial Target User&quot;">​</a></h1><p><strong>Status:</strong> Draft<br><strong>Version:</strong> 0.1</p><h2 id="primary-user" tabindex="-1">Primary User <a class="header-anchor" href="#primary-user" aria-label="Permalink to &quot;Primary User&quot;">​</a></h2><p>The first user is the project creator: a software developer who values privacy, already experiments with self-hosted systems, owns a Raspberry Pi 5 with 16 GB RAM, and wants a useful system in their own home rather than a technology demonstration that is immediately discarded.</p><p>This user can prepare a Raspberry Pi and follow technical installation instructions. They should not need to manually coordinate containers, inspect databases, construct API requests, or read service logs during ordinary use.</p><h2 id="needs" tabindex="-1">Needs <a class="header-anchor" href="#needs" aria-label="Permalink to &quot;Needs&quot;">​</a></h2><ul><li>Operate useful home services without depending on a proprietary cloud ecosystem.</li><li>Understand the state of local services through a coherent interface.</li><li>Ask natural-language questions without granting an AI unrestricted system access.</li><li>Retain ownership of hardware, data, credentials, backups, and provider choices.</li><li>Continue receiving useful core behavior when the internet is unavailable.</li><li>Install, recover, and remove the system through documented procedures.</li></ul><h2 id="initial-context" tabindex="-1">Initial Context <a class="header-anchor" href="#initial-context" aria-label="Permalink to &quot;Initial Context&quot;">​</a></h2><ul><li>One home and one administrator.</li><li>A trusted local network, but not an assumption that every local device is benign.</li><li>A Raspberry Pi dedicated to, or suitable for, persistent services.</li><li>Pi-hole available on the same host or elsewhere on the local network.</li><li>Browser access from a phone, tablet, or computer.</li><li>Limited spare time for ongoing administration.</li></ul><h2 id="success-for-this-user" tabindex="-1">Success for This User <a class="header-anchor" href="#success-for-this-user" aria-label="Permalink to &quot;Success for This User&quot;">​</a></h2><p>Phase 01 succeeds when the user can flash one image, boot the Raspberry Pi, reach Pi-hole at <code>sovereign.local/dns/admin/</code>, and use it as the household DNS service without installing packages or running setup commands. Router DNS configuration remains an explicit external step.</p><h2 id="users-not-yet-targeted" tabindex="-1">Users Not Yet Targeted <a class="header-anchor" href="#users-not-yet-targeted" aria-label="Permalink to &quot;Users Not Yet Targeted&quot;">​</a></h2><ul><li>Non-technical consumers expecting appliance-level installation and support.</li><li>Multi-household or enterprise administrators.</li><li>Users requiring remote access over the public internet.</li><li>Users requiring broad hardware compatibility.</li><li>Plugin developers outside the core project.</li><li>Users seeking a finished voice-assistant replacement in the preview.</li></ul><p>These may become future audiences, but they must not distort the first vertical slice.</p>',14)])])}const m=t(s,[["render",o]]);export{p as __pageData,m as default};
